const solve = (nums) => {
    const N = nums.length;
    if (N === 0) return 0;

    // 1. Precompute Indices[V]: list of indices where value V appears.
    const indices = new Map();
    for (let i = 0; i < N; i++) {
        const val = nums[i];
        if (!indices.has(val)) {
            indices.set(val, []);
        }
        indices.get(val).push(i);
    }

    let totalCount = 0;
    // M_prev stores {OR_value: min_L}, where min_L is the smallest starting index 
    // such that OR(nums[min_L...j-1]) = OR_value.
    let M_prev = new Map();

    // Helper for binary search (finds index of first element >= target)
    const lowerBound = (arr, target) => {
        let low = 0;
        let high = arr.length;
        while (low < high) {
            const mid = Math.floor((low + high) / 2);
            if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    };

    // 2. Iterate j (the end index)
    for (let j = 0; j < N; j++) {
        const num_j = nums[j];
        let M_curr = new Map();

        // Add subarray [j, j]
        M_curr.set(num_j, j);

        // Transition from M_prev (subarrays ending at j-1)
        for (const [O_old, L_old] of M_prev.entries()) {
            const O_new = O_old | num_j;

            // We want to keep the smallest starting index L_old for O_new
            if (!M_curr.has(O_new) || L_old < M_curr.get(O_new)) {
                M_curr.set(O_new, L_old);
            }
        }

        M_prev = M_curr;

        // 3. Process the segments defined by M_j = M_prev

        // Convert map entries to an array of [O, L] pairs and sort by L ascending
        const segments = Array.from(M_prev.entries())
            .map(([O, L]) => ({ O, L }))
            .sort((a, b) => a.L - b.L);

        const K = segments.length;

        // Iterate through segments to determine ranges and check the condition
        for (let r = 0; r < K; r++) {
            const seg = segments[r];
            const O_r = seg.O;
            const L_r = seg.L;

            // Determine the end of this segment: L_{r+1} - 1, or j if r is the last segment
            const L_next = (r + 1 < K) ? segments[r + 1].L : j + 1;
            const L_end = Math.min(j, L_next - 1);

            // The range of starting indices i for this OR value O_r is [L_r, L_end]
            const count = L_end - L_r + 1;

